import{_ as r,o as a,c as t,Y as o,Z as l}from"./chunks/framework.vRQslyNc.js";import"./chunks/theme.B1uNNMqp.js";const m=JSON.parse('{"title":"作者","description":"","frontmatter":{"title":"作者","layout":"home","date":"2022-12-12T13:42:34.000Z","updated":"2022-12-12T13:42:34.000Z"},"headers":[],"relativePath":"author.md","filePath":"author.md"}'),s={name:"author.md"};function i(h,e,n,p,d,c){return a(),t("div",null,[...e[0]||(e[0]=[o('<p><img src="'+l+'" alt="头像由 PixelMe (xsgames.co/pixelme) 生成" loading="lazy"></p><h2 id="碎碎念" tabindex="-1">碎碎念 <a class="header-anchor" href="#碎碎念" aria-label="Permalink to “碎碎念”">​</a></h2><p>这是一个普通开发者记录技术成长的博客，内容可能不够深入，但都是真实的实践经历。</p><h3 id="起步-2018-年的探索" tabindex="-1">起步：2018 年的探索 <a class="header-anchor" href="#起步-2018-年的探索" aria-label="Permalink to “起步：2018 年的探索”">​</a></h3><p>最初的动力源于对 Linux 系统的好奇。为了深入学习，我购买了阿里云的轻量服务器，开始了&quot;折腾&quot;之旅：配置 IP、绑定域名、安装 Docker，这些基础操作让我对服务器管理有了初步认识。</p><h3 id="hexo-时代-博客初体验" tabindex="-1">Hexo 时代：博客初体验 <a class="header-anchor" href="#hexo-时代-博客初体验" aria-label="Permalink to “Hexo 时代：博客初体验”">​</a></h3><p>看到网上众多技术博客后，我也萌生了写博客的想法。经过调研，选择了 <a href="https://hexo.io/" target="_blank" rel="noreferrer">Hexo</a> 作为博客框架，并采用了美观的 <a href="https://hexo.fluid-dev.com/" target="_blank" rel="noreferrer">Fluid 主题</a>。在学习过程中，参考了 <a href="https://hexo.fluid-dev.com/" target="_blank" rel="noreferrer">Fluid&#39;s blog</a> 的 <a href="https://hexo.fluid-dev.com/posts/actions-deploy/" target="_blank" rel="noreferrer">利用 GitHub Actions 自动部署 Hexo 博客</a>教程，不仅成功搭建了博客，还根据教程完善了内容展示和样式设计。</p><h3 id="自动化部署-技术栈扩展" tabindex="-1">自动化部署：技术栈扩展 <a class="header-anchor" href="#自动化部署-技术栈扩展" aria-label="Permalink to “自动化部署：技术栈扩展”">​</a></h3><p>有了服务器后，自然想实现自动化部署。这期间学习了：</p><ul><li><a href="https://www.drone.io/" target="_blank" rel="noreferrer">Drone</a> - 持续集成工具</li><li><a href="https://nginx.org/" target="_blank" rel="noreferrer">Nginx</a> - Web 服务器</li><li><a href="https://docs.docker.com/compose/" target="_blank" rel="noreferrer">Docker Compose</a> - 容器编排</li></ul><p>通过这些技术的组合，成功搭建了完整的自动化部署流程。</p><h3 id="中断与重启-2025-年的回归" tabindex="-1">中断与重启：2025 年的回归 <a class="header-anchor" href="#中断与重启-2025-年的回归" aria-label="Permalink to “中断与重启：2025 年的回归”">​</a></h3><p>随着工作忙碌和家庭琐事增多，博客更新逐渐停滞。直到 2025 年，重新燃起技术分享的热情，决定重启博客。</p><h3 id="新的征程-vitepress-时代" tabindex="-1">新的征程：VitePress 时代 <a class="header-anchor" href="#新的征程-vitepress-时代" aria-label="Permalink to “新的征程：VitePress 时代”">​</a></h3><p>重启之初尝试了 <a href="https://www.vuepress.cn/" target="_blank" rel="noreferrer">VuePress</a>，在学习 Vue 相关知识的过程中，发现了更轻量、更快速的 <a href="https://vitepress.dev/zh/" target="_blank" rel="noreferrer">VitePress</a>。VitePress 的简洁设计和优秀性能更符合我的需求，于是便迁移到了 VitePress，开启了新的博客之旅。</p>',15)])])}const u=r(s,[["render",i]]);export{m as __pageData,u as default};
